const raw = (typeof msg.payload === 'string'
    ? msg.payload
    : String(msg.payload)
).trim();

msg.rawMessage = raw;

function parseCell(token) {
    const m = token.match(/^(\d+)\.(\d+)\.([0-9a-fA-F]+)\.([0-9a-fA-F]+)@(-?\d+)$/);
    if (!m) return null;
    return {
        mobileCountryCode: parseInt(m[1], 10),
        mobileNetworkCode: parseInt(m[2], 10),
        locationAreaCode:  parseInt(m[3], 16),
        cellId:            parseInt(m[4], 16),
        signalStrength:    parseInt(m[5], 10)
    };
}

const sosMatch = raw.match(/^SOS\s+IMEI:(\d+);?$/i);
if (sosMatch) {
    msg.imei = sosMatch[1];
    msg.isSOS = true;
    msg.topic = 'sos';
    msg.serving = null;
    msg.neighbors = [];
    node.status({ fill:'red', shape:'dot', text:'SOS from ' + msg.imei });
    return [null, msg];
}

const imeiMatch    = raw.match(/IMEI:(\d+)/);
const serviceMatch = raw.match(/service:\[([^\]]+)\]/);
const neighborRe   = /\[([^\]]+)\]/g;

if (!imeiMatch || !serviceMatch) {
    node.error('Unparseable message: ' + raw, msg);
    return [null, null];
}

const serving = parseCell(serviceMatch[1]);
if (!serving) {
    node.error('Unparseable serving cell: ' + serviceMatch[1], msg);
    return [null, null];
}

const neighbors = [];
let nm;
let skipFirst = true;
while ((nm = neighborRe.exec(raw)) !== null) {
    if (skipFirst) { skipFirst = false; continue; }
    const c = parseCell(nm[1]);
    if (c) neighbors.push(c);
}

msg.imei      = imeiMatch[1];
msg.isSOS     = false;
msg.topic     = 'location';
msg.serving   = serving;
msg.neighbors = neighbors;

msg.geoBody = {
    radioType: 'gsm',
    considerIp: true,
    cellTowers: [serving, ...neighbors]
};

node.status({ fill:'green', shape:'dot', text: msg.imei + ' · ' + (1+neighbors.length) + ' towers' });
return [msg, null];

const apiKey = env.get('GOOGLE_GEO_API_KEY') || 'write your google geolocation API key';
if (!apiKey || apiKey === 'YOUR_API_KEY') {
    node.warn('GOOGLE_GEO_API_KEY not set!');
}
msg.url     = 'https://www.googleapis.com/geolocation/v1/geolocate?key=' + apiKey;
msg.method  = 'POST';
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = {
    radioType: 'gsm',
    homeMobileCountryCode: 208,
    homeMobileNetworkCode: 1,
    considerIp: true,
    cellTowers: [msg.serving, ...msg.neighbors]
};
return msg;

if (!msg.payload || msg.payload.error) {
    const err = msg.payload && msg.payload.error ? msg.payload.error.message : 'Unknown error';
    node.warn('Geolocation API error: ' + err);
    msg.lat      = null;
    msg.lng      = null;
    msg.accuracy = null;
} else {
    msg.lat      = msg.payload.location.lat;
    msg.lng      = msg.payload.location.lng;
    msg.accuracy = msg.payload.accuracy;
}

const watches = flow.get('watches') || {};
if (!watches[msg.imei]) {
    watches[msg.imei] = {
        imei:      msg.imei,
        lat:       msg.lat,
        lng:       msg.lng,
        accuracy:  msg.accuracy,
        sos:       msg.isSOS || false,
        serving:   msg.serving,
        neighbors: msg.neighbors,
        updatedAt: new Date().toISOString()
    };
} else {
    watches[msg.imei].lat       = msg.lat;
    watches[msg.imei].lng       = msg.lng;
    watches[msg.imei].accuracy  = msg.accuracy;
    watches[msg.imei].sos       = msg.isSOS || false;
    watches[msg.imei].updatedAt = new Date().toISOString();
}
flow.set('watches', watches);

msg.topic   = msg.isSOS ? 'sos' : 'location';
msg.payload = watches[msg.imei];

node.status({
    fill:  msg.lat ? 'green' : 'yellow',
    shape: 'dot',
    text:  msg.imei + ' → ' + (msg.lat ? msg.lat.toFixed(4)+','+msg.lng.toFixed(4) : 'no fix')
});

return msg;

const watches = flow.get('watches') || {};
if (!watches[msg.imei]) {
    watches[msg.imei] = {
        imei: msg.imei,
        lat: null, lng: null, accuracy: null,
        sos: true,
        serving: null,
        neighbors: [],
        updatedAt: new Date().toISOString()
    };
} else {
    watches[msg.imei].sos = true;
    watches[msg.imei].updatedAt = new Date().toISOString();
}
flow.set('watches', watches);

msg.payload = watches[msg.imei];
msg.topic   = 'sos';
msg.isSOS   = true;

const locStr = watches[msg.imei].lat
    ? watches[msg.imei].lat.toFixed(4) + ',' + watches[msg.imei].lng.toFixed(4)
    : 'unknown location';

msg.sosText = '⚠ SOS — IMEI ' + msg.imei + ' at ' + locStr + ' (' + new Date().toLocaleTimeString() + ')';

return msg;

const w = msg.payload;
if (!w.lat) return null;

msg.payload = {
    name:      w.imei,
    lat:       w.lat,
    lon:       w.lng,
    icon:      w.sos ? 'danger' : 'circle',
    iconColor: w.sos ? 'red' : 'blue',
    label:     w.imei.slice(-4),
    popup:     '<b>' + (w.sos ? '⚠ SOS — ' : '') + w.imei + '</b><br>' +
               'Lat: ' + w.lat.toFixed(5) + '<br>' +
               'Lng: ' + w.lng.toFixed(5) + '<br>' +
               '±' + Math.round(w.accuracy || 0) + ' m<br>' +
               'Updated: ' + w.updatedAt
};
return msg;

const watches = flow.get('watches') || {};
const rows = Object.values(watches).map(w => ({
    imei:      w.imei,
    sos:       w.sos,
    lat:       w.lat  != null ? w.lat.toFixed(5)  : '—',
    lng:       w.lng  != null ? w.lng.toFixed(5)  : '—',
    accuracy:  w.accuracy != null ? Math.round(w.accuracy) + ' m' : '—',
    updatedAt: w.updatedAt
}));
msg.payload = rows;
return msg;
